module top_module(
  input [11:0] obf_I,
  input [3:0] S,
  output reg O
);always @ (S or obf_I) begin
    case(S)
      4'd0: O = obf_I[0];
      4'd1: O = obf_I[1];
      4'd2: O = obf_I[2];
      4'd3: O = obf_I[3];
      4'd4: O = obf_I[4];
      4'd5: O = obf_I[5];
      4'd6: O = obf_I[6];
      4'd7: O = obf_I[7];
      4'd8: O = obf_I[8];
      4'd9: O = obf_I[9];
      4'd10: O = obf_I[10];
      4'd11: O = obf_I[11];
      default: O = 1'b0;
    endcase
  end

endmodule
